-- Apply 30 FAQs to all 36 visa services (one paste in SQL Editor)
-- Does NOT touch quiz questions — only patches academy_metadata.faqs
-- After run, execute 00-diagnose-faq-counts.sql → expect done_30 = 36

-- Canada – Student Visa (Study Permit — Outside Canada) — 30 FAQs
-- Source: content/service-library/canada-student-visa.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we switch from SDS to Non-SDS if SDS is paused?","a":"Yes, when the client is SDS-ineligible or SDS is unavailable. Rebuild the file per Non-SDS checklist and update fee quote (no GIC requirement unless otherwise applicable)."},{"q":"How much funds to show for Non-SDS?","a":"Tuition for first year plus living expenses per IRCC guidelines (amounts update—verify on canada.ca). Include credible source of funds and history."},{"q":"When should biometrics be done?","a":"As soon as possible after Biometric Instruction Letter (BIL), typically within 30 days. Counselor should track VAC appointment confirmation."},{"q":"Can spouse/children accompany?","a":"May require separate applications (visitor permit, OWP, study permit for children). Assess dependants case-by-case; extra funds and ties evidence needed."},{"q":"What if LOA start date is near?","a":"Apply urgently; explain delay if any. If start date passed, obtain updated LOA before submission."},{"q":"Is medical mandatory for everyone?","a":"No—depends on country of residence and stay duration. Follow IRCC medical instructions for the client''s profile."},{"q":"Can client work on study permit?","a":"Generally on-campus without separate permit; off-campus rules have hour limits—cite current IRCC rules at time of counseling."},{"q":"What happens after study permit approval?","a":"Client receives introduction letter; permit issued at port of entry or as directed. Remind client to maintain full-time status and keep contact details updated with IRCC."},{"q":"What is Description for this service?","a":"Study permit allowing international students to study at a Designated Learning Institution (DLI) in Canada. This service is for applicants applying from outside Canada before travel; application is typically online via IRCC portal, and biometrics and medical may apply."},{"q":"What is Eligible applicants for this service?","a":"Valid LOA from DLI · Proof of funds · Clean immigration history · Genuine student intent"},{"q":"What is Application streams for this service?","a":"SDS (where eligible): faster processing with GIC and language scores. Non-SDS: standard study permit pathway."},{"q":"Important note on Application streams?","a":"SDS (where eligible): faster processing with GIC and language scores. Non-SDS: standard study permit pathway."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Client receives POE letter / permit details; explain study conditions, work limits, and DLI enrollment obligations."},{"q":"Is Letter of acceptance (LOA) from DLI required?","a":"LOA must be valid and program start date realistic"},{"q":"Is Proof of financial support (tuition + living) required?","a":"SDS: GIC + tuition payment proof where required"},{"q":"Is Language proficiency (SDS) required?","a":"IELTS/TOEFL/PTE per SDS country list"},{"q":"Is Biometrics completed required?","a":"Book within 30 days of BIL if required"},{"q":"Is Medical exam (if required) required?","a":"Based on residence history and IRCC instructions"},{"q":"Is No criminal / immigration misrepresentation required?","a":"No criminal / immigration misrepresentation is typically required."},{"q":"Is Genuine student / ties to home country required?","a":"SOP and career plan must align"},{"q":"What is the Processing time?","a":"8–12w — Varies by country & stream"},{"q":"What is the Government fee?","a":"CAD $150 — + biometrics if applicable"},{"q":"What is the Our approval rate?","a":"87% — ~72% industry benchmark"},{"q":"What is the Required docs?","a":"14 — + conditional items"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has Insufficient or unseasoned funds?","a":"Season funds early; use GIC for SDS; sponsor ITR + employment letters"},{"q":"Why is Insufficient or unseasoned funds a problem?","a":"Large recent deposits, funds not aligned with sponsor income, or missing 4–6 month bank history."},{"q":"What if the client has Weak or generic SOP?","a":"Course-specific SOP; link prior study/work to Canada program; clear post-study plan"},{"q":"Why is Weak or generic SOP a problem?","a":"Template SOP, course mismatch with past education, or unclear return intent."}]'::jsonb
),
updated_at = now()
WHERE id = 'c35e6051-f40f-47bf-9cac-0a386c47a336';

-- Canada – Visitor Visa (TRV) — 30 FAQs
-- Source: content/service-library/canada-visitor-visa.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee approval for a strong profile?","a":"No. IRCC officers assess each case individually. We can improve file quality but never promise approval."},{"q":"How much funds should a tourist show?","a":"Enough to cover flights, accommodation, and daily expenses for the planned stay. Verify current IRCC guidance; typically CAD $2,000–5,000+ depending on duration and who pays."},{"q":"Is an invitation letter mandatory for family visits?","a":"Not always legally required, but strongly recommended when visiting relatives. Host should provide invitation, status proof, and address details."},{"q":"Can a refused applicant reapply?","a":"Yes, when circumstances or evidence materially improve. Reapply without addressing refusal reasons usually fails again."},{"q":"Does TRV allow work in Canada?","a":"No. TRV is for temporary visit only. Work requires a work permit unless exempt."},{"q":"How long can a visitor stay?","a":"Officer sets duration at port of entry—often up to 6 months per entry. Client must not overstay."},{"q":"When should biometrics be done?","a":"As soon as possible after Biometric Instruction Letter, typically within 30 days."},{"q":"Can TRV be used to join a spouse studying in Canada?","a":"Sometimes, but assess whether visitor visa or dependant permit is more appropriate. Separate pathways may apply."},{"q":"What is Description for this service?","a":"Temporary Resident Visa (TRV) allowing Indian nationals to visit Canada for tourism, family visits, or short business trips. Most applications are submitted online through the IRCC portal."},{"q":"What is Eligible applicants for this service?","a":"Valid passport · Genuine temporary purpose · Strong ties to India · Sufficient funds · Clean immigration history"},{"q":"What is Single vs multiple entry for this service?","a":"Officer decides entry type and validity at approval. Do not promise multiple-entry unless client profile supports it."},{"q":"Important note on Single vs multiple entry?","a":"Officer decides entry type and validity at approval. Do not promise multiple-entry unless client profile supports it."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"TRV counterfoil in passport; client must respect stay duration and purpose. Overstay affects future Canada applications."},{"q":"Is Valid passport (6+ months validity recommended) required?","a":"Check expiry before booking VAC appointment"},{"q":"Is Proof of purpose (tourism / family / business) required?","a":"Itinerary, invitation letter, or business documents as applicable"},{"q":"Is Proof of funds for trip duration required?","a":"Bank statements, ITR, sponsor letter if applicable"},{"q":"Is Strong ties to home country required?","a":"Employment, property, family, business—document clearly"},{"q":"Is Biometrics completed required?","a":"Book within 30 days of BIL if required"},{"q":"Is Medical exam (if required) required?","a":"Based on residence history and stay plans"},{"q":"Is No prior misrepresentation or serious inadmissibility required?","a":"No prior misrepresentation or serious inadmissibility is typically required."},{"q":"What is the Processing time?","a":"2–8w — Varies by country of residence"},{"q":"What is the Government fee?","a":"CAD $100 — + biometrics CAD $85 if required"},{"q":"What is the Our approval rate?","a":"78% — ~65% industry benchmark"},{"q":"What is the Required docs?","a":"10 — + invitation if applicable"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has Weak home-country ties?","a":"Document employment, business, property, family obligations; employer leave letter"},{"q":"Why is Weak home-country ties a problem?","a":"Unemployed applicant with no property, family, or business ties; vague return plan."},{"q":"What if the client has Insufficient or unseasoned funds?","a":"4–6 month bank history; sponsor ITR + employment letter; explain large credits"},{"q":"Why is Insufficient or unseasoned funds a problem?","a":"Large recent deposits, funds not matching income, or no sponsor proof."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000011';

-- Canada – Spouse / Partner Sponsorship — 30 FAQs
-- Source: content/service-library/canada-spouse-visa.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee PR approval for a genuine marriage?","a":"No. Even genuine couples can face requests for additional evidence or refusal if documentation is weak. We improve file quality but never promise approval."},{"q":"Inland or outland—which is faster?","a":"Timelines vary and change. Outland may allow partner to visit during processing; inland may offer open work permit eligibility. Assess case-by-case."},{"q":"How much relationship evidence is enough?","a":"No fixed amount—officers want a credible chronological story: how you met, communication, visits, marriage, shared life plans. Quality over quantity."},{"q":"Can a sponsored spouse work while waiting?","a":"Inland applicants may apply for open work permit after AIP stage in many cases. Verify current IRCC rules at time of counseling."},{"q":"What if marriage is recent?","a":"Recent marriages need stronger evidence—communication history before marriage, visit records, photos, and explanation of relationship development."},{"q":"Does sponsor need minimum income?","a":"Spousal sponsorship generally has no LICO requirement for spouse/partner/child, but sponsor must not be on social assistance (except disability) and must meet undertaking obligations."},{"q":"What happens after refusal?","a":"Review refusal letter carefully. Options may include appeal (IAD) for in-Canada refusals in some cases, or reapplication with stronger evidence."},{"q":"Are common-law partners eligible?","a":"Yes, if they have cohabited continuously for at least 12 months. Evidence of shared residence is essential."},{"q":"What is Description for this service?","a":"Family class sponsorship allowing a Canadian citizen or permanent resident to sponsor a spouse, common-law, or conjugal partner for permanent residence. Outland applications processed from abroad; inland if partner is in Canada."},{"q":"What is Eligible applicants for this service?","a":"Legally married or qualifying common-law/conjugal relationship · Sponsor meets income/residency requirements · Genuine relationship · Medical and security clearances"},{"q":"What is Inland vs outland for this service?","a":"Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision."},{"q":"Important note on Inland vs outland?","a":"Outland: partner outside Canada, can visit during processing. Inland: partner in Canada; may qualify for open work permit while awaiting decision."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Partner receives COPR and completes landing. Maintain relationship genuineness obligations; misrepresentation has serious consequences."},{"q":"Is Sponsor is Canadian citizen or PR aged 18+ required?","a":"Verify sponsor status and residency obligations"},{"q":"Is Legally valid marriage or qualifying relationship required?","a":"Marriage certificate; common-law needs 12+ months cohabitation proof"},{"q":"Is Genuine relationship evidence required?","a":"Photos, communication, financial mingling, visits"},{"q":"Is Sponsor not in default of prior sponsorship undertakings required?","a":"Sponsor not in default of prior sponsorship undertakings is typically required."},{"q":"Is Medical exam completed required?","a":"Panel physician after instructions"},{"q":"Is Police certificates as required required?","a":"Based on residence history"},{"q":"Is Biometrics completed required?","a":"Both sponsor and applicant if required"},{"q":"What is the Processing time?","a":"12–18m — Varies by stream and office"},{"q":"What is the Government fee?","a":"CAD $1,150+ — + biometrics, medical"},{"q":"What is the Our approval rate?","a":"91% — ~82% industry benchmark"},{"q":"What is the Required docs?","a":"18 — + relationship evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has Weak relationship evidence?","a":"Chronological timeline; chat/call logs; joint finances; visit stamps; affidavits from family"},{"q":"Why is Weak relationship evidence a problem?","a":"Few photos, no communication logs, short relationship timeline, or inconsistent stories."},{"q":"What if the client has Marriage of convenience suspicion?","a":"Honest narrative; explain how relationship developed; strong third-party support"},{"q":"Why is Marriage of convenience suspicion a problem?","a":"Large age gap without explanation, met only days before marriage, or prior failed sponsorships."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000012';

-- Canada – Express Entry (Permanent Residence) — 30 FAQs
-- Source: content/service-library/canada-express-entry-pr.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee ITA or PR?","a":"No. CRS cutoffs change each draw. We improve profile quality but never promise ITA or approval."},{"q":"What CRS score needed?","a":"Varies each draw—check recent IRCC draw results. Category-based draws have different cutoffs."},{"q":"How to improve CRS?","a":"Higher language scores, additional education ECA, Canadian work experience, PNP nomination (+600), French language bonus."},{"q":"What is PNP?","a":"Provincial Nominee Program—province nomination adds 600 CRS points, virtually ensuring ITA."},{"q":"Processing after ITA?","a":"Typically 6 months standard for most EE applications—verify current IRCC processing times."},{"q":"Can spouse be included?","a":"Yes—spouse factors into CRS; include if beneficial to score."},{"q":"Proof of funds when?","a":"Required at ITA stage for FSW; amount per family size on canada.ca."},{"q":"What if ITA declined?","a":"Profile may re-enter pool if valid—assess options carefully."},{"q":"What is Description for this service?","a":"Federal economic immigration system managing FSW, CEC, and FST programs. Candidates create profile, receive CRS score, and apply for PR if invited (ITA)."},{"q":"What is Eligible applicants for this service?","a":"Meet FSW/CEC/FST criteria · Valid language tests · ECA for foreign education · Sufficient CRS score · Medical and police clearances"},{"q":"What is ITA not guaranteed for this service?","a":"Profile in pool does not guarantee invitation. CRS cutoffs vary per draw. PNP can add 600 points."},{"q":"Important note on ITA not guaranteed?","a":"Profile in pool does not guarantee invitation. CRS cutoffs vary per draw. PNP can add 600 points."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"COPR issued; complete landing; apply for PR card. Meet residency obligations for citizenship pathway."},{"q":"Is Eligible program (FSW/CEC/FST) required?","a":"Eligible program (FSW/CEC/FST) is typically required."},{"q":"Is Language test (CLB minimum per program) required?","a":"Language test (CLB minimum per program) is typically required."},{"q":"Is ECA for foreign credentials (FSW) required?","a":"WES/IQAS etc."},{"q":"Is CRS score competitive for recent draws required?","a":"Assess against recent cutoffs"},{"q":"Is Work experience documented (NOC/TEER) required?","a":"Work experience documented (NOC/TEER) is typically required."},{"q":"Is Proof of funds (FSW/ FST if applicable) required?","a":"Proof of funds (FSW/ FST if applicable) is typically required."},{"q":"Is Medical and police completed after ITA required?","a":"Assess whether Medical and police completed after ITA is satisfied for this case."},{"q":"What is the Processing time?","a":"6–12m — After ITA received"},{"q":"What is the Government fee?","a":"CAD $1,525+ — PR application after ITA"},{"q":"What is the Our approval rate?","a":"94% — ~88% post-ITA benchmark"},{"q":"What is the Required docs?","a":"16 — + ECA, language, work ref"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & ECA/tests"},{"q":"What if the client has CRS below recent draw cutoffs?","a":"Retake language for higher CLB; pursue PNP; gain Canadian work experience"},{"q":"Why is CRS below recent draw cutoffs a problem?","a":"Client expects ITA with non-competitive score."},{"q":"What if the client has Wrong NOC/TEER code?","a":"Verify TEER category against official duties and reference letters"},{"q":"Why is Wrong NOC/TEER code a problem?","a":"Work experience coded incorrectly affecting points."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000013';

-- Canada – Post-Graduation Work Permit (PGWP) — 30 FAQs
-- Source: content/service-library/canada-pgwp.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee PGWP approval?","a":"No. IRCC verifies eligibility. Most eligible graduates are approved but we never guarantee."},{"q":"How long is PGWP?","a":"Depends on program length—8 months minimum program for any PGWP; up to 3 years for 2+ year programs."},{"q":"Can apply from outside Canada?","a":"Generally must apply within 180 days while eligible—rules vary if outside Canada. Verify current instructions."},{"q":"Can work while waiting?","a":"If applied before study permit expiry, may work under implied status—verify current rules."},{"q":"PGWP and Express Entry?","a":"Canadian work experience on PGWP counts toward CEC—key PR pathway."},{"q":"Second PGWP possible?","a":"Generally one PGWP per lifetime—exceptions rare."},{"q":"Online vs paper?","a":"Online via IRCC portal recommended."},{"q":"Spouse work permit?","a":"Spouse may qualify for open work permit if PGWP holder meets skill level—verify current rules."},{"q":"What is Description for this service?","a":"Open work permit allowing international graduates of eligible DLIs to work in Canada after completing program. Duration linked to program length."},{"q":"What is Eligible applicants for this service?","a":"Completed eligible program at DLI · Valid study permit · Graduation confirmation · Applied within 180 days of completion letter"},{"q":"What is Duration rules for this service?","a":"Program 8 months–2 years: PGWP may match program length. 2+ years: up to 3 years. Verify current IRCC rules."},{"q":"Important note on Duration rules?","a":"Program 8 months–2 years: PGWP may match program length. 2+ years: up to 3 years. Verify current IRCC rules."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Work anywhere in Canada. PGWP time supports CEC pathway to PR via Express Entry."},{"q":"Is Graduated from eligible DLI program required?","a":"Graduated from eligible DLI program is typically required."},{"q":"Is Valid study permit at completion required?","a":"Valid study permit at completion is typically required."},{"q":"Is Completion letter / transcript required?","a":"Completion letter / transcript is typically required."},{"q":"Is Applied within 180 days of completion required?","a":"Critical deadline"},{"q":"Is Full-time student status maintained required?","a":"Full-time student status maintained is typically required."},{"q":"Is Passport valid through desired PGWP period required?","a":"Passport valid through desired PGWP period is typically required."},{"q":"Is Not previously received PGWP required?","a":"One-time rule"},{"q":"What is the Processing time?","a":"3–5m — Online application"},{"q":"What is the Government fee?","a":"CAD $255 — Verify on canada.ca"},{"q":"What is the Our approval rate?","a":"92% — ~85% benchmark"},{"q":"What is the Required docs?","a":"8 — + completion letter"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"},{"q":"What if the client has Applied after 180-day deadline?","a":"Apply within 180 days or restore status if eligible"},{"q":"Why is Applied after 180-day deadline a problem?","a":"Completion letter date exceeded 180 days."},{"q":"What if the client has Program too short?","a":"Verify eligibility before completion; plan alternative"},{"q":"Why is Program too short a problem?","a":"Program under 8 months generally ineligible."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000014';

-- Canada – Work Permit (LMIA & LMIA-Exempt) — 30 FAQs
-- Source: content/service-library/canada-work-permit.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee work permit?","a":"No. Both ESDC (LMIA) and IRCC must approve where applicable."},{"q":"LMIA processing time?","a":"Varies—often 2–5 months for standard LMIA. Verify current ESDC service standards."},{"q":"LMIA-exempt categories?","a":"Includes ICT transfers, CUSMA professionals, PGWP, spousal open permits, etc.—verify exemption code."},{"q":"Can spouse work?","a":"Spouse may qualify for open work permit in some categories—verify current rules."},{"q":"Employer costs for LMIA?","a":"LMIA application fee CAD $1,000 per position; plus recruitment costs."},{"q":"Can apply at border?","a":"Some nationals may flagpole—verify eligibility and current policy."},{"q":"Work permit and PR pathway?","a":"Canadian experience may support CEC via Express Entry."},{"q":"What if LMIA refused?","a":"Review ESDC reasons; address recruitment or wage issues; reapply or explore exempt categories."},{"q":"What is Description for this service?","a":"Employer-specific or open work permit allowing foreign nationals to work in Canada. LMIA-required streams need positive LMIA from Employment and Social Development Canada (ESDC)."},{"q":"What is Eligible applicants for this service?","a":"Valid job offer from Canadian employer · LMIA or exempt category · Qualifying skills/experience · Medical/biometrics as required"},{"q":"What is LMIA process for this service?","a":"Employer must advertise, recruit, and demonstrate no Canadians available. ESDC LMIA adds weeks to months before IRCC application."},{"q":"Important note on LMIA process?","a":"Employer must advertise, recruit, and demonstrate no Canadians available. ESDC LMIA adds weeks to months before IRCC application."},{"q":"What is Key authority for this service?","a":"ESDC (LMIA) · IRCC (work permit)"},{"q":"What is After approval for this service?","a":"Work for specified employer (closed permit) or open category. Maintain status; employer compliance with LMIA conditions."},{"q":"Is Valid job offer / contract required?","a":"Valid job offer / contract is typically required."},{"q":"Is LMIA positive or exempt category confirmed required?","a":"Employer responsibility for LMIA"},{"q":"Is Qualifying work experience/education required?","a":"Qualifying work experience/education is typically required."},{"q":"Is Medical exam (if required) required?","a":"Assess whether Medical exam (if required) is satisfied for this case."},{"q":"Is Biometrics completed required?","a":"Assess whether Biometrics completed is satisfied for this case."},{"q":"Is No criminal inadmissibility required?","a":"No criminal inadmissibility is typically required."},{"q":"Is Employer compliance history required?","a":"Verify employer legitimacy"},{"q":"What is the Processing time?","a":"3–9m — LMIA + IRCC combined"},{"q":"What is the Government fee?","a":"CAD $155 — Worker fee + biometrics"},{"q":"What is the Our approval rate?","a":"86% — ~78% benchmark"},{"q":"What is the Required docs?","a":"15 — + LMIA if applicable"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & LMIA"},{"q":"What if the client has LMIA advertising deficiencies?","a":"Ensure ESDC advertising compliance before LMIA submit"},{"q":"Why is LMIA advertising deficiencies a problem?","a":"Employer did not meet recruitment advertising requirements."},{"q":"What if the client has Wrong NOC/ wage offer?","a":"Verify TEER and prevailing wage on Job Bank"},{"q":"Why is Wrong NOC/ wage offer a problem?","a":"Job classification or wage below median for region."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000015';

-- Canada – Super Visa (Parents & Grandparents) — 30 FAQs
-- Source: content/service-library/canada-super-visa.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee Super Visa approval?","a":"No. IRCC assesses medical, insurance, LICO, and ties. Never promise approval."},{"q":"How much income sponsor needs?","a":"Verify current LICO table on canada.ca for family size including sponsoring household."},{"q":"Which insurance companies?","a":"Must be Canadian company offering Super Visa compliant coverage—verify with insurer."},{"q":"Difference from regular TRV?","a":"Super Visa allows up to 5-year stays per entry; higher LICO and insurance requirements."},{"q":"Can both parents apply together?","a":"Yes; assess combined documentation and sponsor income for family size."},{"q":"Medical exam when?","a":"Before application; use IRCC panel physician."},{"q":"Processing time from India?","a":"Often 3–8 months—check current IRCC processing times."},{"q":"Can Super Visa holder work?","a":"No. Visit and family time only—not employment."},{"q":"What is Description for this service?","a":"Multi-entry visa allowing parents and grandparents of Canadian citizens/PRs to visit for up to 5 years per entry without renewing status."},{"q":"What is Eligible applicants for this service?","a":"Parent/grandparent of Canadian citizen or PR · Child/grandchild meets LICO income threshold · Medical exam · Canadian medical insurance · Ties to home country"},{"q":"What is Insurance requirement for this service?","a":"Private medical insurance from Canadian company valid minimum 1 year from entry, $100,000 minimum coverage."},{"q":"Important note on Insurance requirement?","a":"Private medical insurance from Canadian company valid minimum 1 year from entry, $100,000 minimum coverage."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Multi-entry visa; maintain valid insurance on each visit; respect super visa conditions."},{"q":"Is Child/grandchild is Canadian citizen or PR required?","a":"Child/grandchild is Canadian citizen or PR is typically required."},{"q":"Is Sponsor meets LICO minimum income required?","a":"3 years Notice of Assessment"},{"q":"Is Medical exam completed required?","a":"Required for Super Visa"},{"q":"Is Canadian medical insurance arranged required?","a":"$100,000 min, 1 year validity"},{"q":"Is Invitation letter from child/grandchild required?","a":"Invitation letter from child/grandchild is typically required."},{"q":"Is Biometrics completed required?","a":"Assess whether Biometrics completed is satisfied for this case."},{"q":"Is Ties to home country (India) required?","a":"Ties to home country (India) is typically required."},{"q":"What is the Processing time?","a":"3–8m — Varies by office"},{"q":"What is the Government fee?","a":"CAD $100 — + biometrics + insurance"},{"q":"What is the Our approval rate?","a":"81% — ~70% benchmark"},{"q":"What is the Required docs?","a":"12 — + insurance policy"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & insurance"},{"q":"What if the client has Insurance non-compliant?","a":"Purchase IRCC-compliant Super Visa insurance before apply"},{"q":"Why is Insurance non-compliant a problem?","a":"Coverage below $100,000 or not from Canadian insurer."},{"q":"What if the client has LICO income not met?","a":"Verify LICO table; combine spouse income if applicable"},{"q":"Why is LICO income not met a problem?","a":"Sponsor income below minimum for family size."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000016';

-- Canada – BOWP (Bridging Open Work Permit) — 30 FAQs
-- Source: content/service-library/canada-bowp.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can every PR applicant get a BOWP?","a":"No. Only specific PR classes and processing stages qualify. Verify current IRCC BOWP instructions for the client''s exact pathway."},{"q":"Is an Express Entry profile enough?","a":"No. The client generally needs a submitted PR application and AOR after invitation, not just an active profile."},{"q":"Can the client keep working after applying?","a":"If they applied before their current work permit expired and meet maintained status rules, they may be able to continue under previous conditions. Confirm facts before advising."},{"q":"Can a BOWP be employer-specific?","a":"BOWP is usually open, but some PNP or Quebec-linked cases may have restrictions or separate requirements."},{"q":"What if the current permit expires next week?","a":"Prioritize same-day document review and submission if eligible. Missing the expiry date can force restoration and stop work."},{"q":"Can spouse or dependants apply too?","a":"They may have separate eligibility for open work permit, study permit, or visitor status. Do not bundle without assessing each dependant."},{"q":"Does BOWP guarantee PR approval?","a":"No. It only supports temporary work status while the PR application is processed."},{"q":"How long is the BOWP issued for?","a":"IRCC decides based on program rules, passport validity, and processing context. Counselors should avoid promising a fixed duration."},{"q":"Can the client travel while BOWP is processing?","a":"Travel can affect re-entry and work authorization. Review TRV/eTA, status, and risk before travel."},{"q":"What if PR is refused while BOWP is valid?","a":"Temporary status must be reassessed immediately. The client may need a new status strategy before the work permit expires."},{"q":"What is Description for this service?","a":"Bridging Open Work Permit for eligible in-Canada applicants who have submitted certain permanent residence applications and need to keep working while PR is processed."},{"q":"What is Eligible applicants for this service?","a":"In Canada · Valid status or eligible restoration · Submitted eligible PR application · Received AOR or passed completeness check where required"},{"q":"What is Eligible PR classes for this service?","a":"Commonly Express Entry, Provincial Nominee Program, Agri-Food Pilot, and certain caregiver or Quebec skilled worker pathways. Verify current IRCC program list."},{"q":"Important note on Eligible PR classes?","a":"Commonly Express Entry, Provincial Nominee Program, Agri-Food Pilot, and certain caregiver or Quebec skilled worker pathways. Verify current IRCC program list."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Client may work in Canada under open work permit conditions while PR continues. Review province restrictions for some nominee cases."},{"q":"Is Client is physically in Canada when applying required?","a":"Client is physically in Canada when applying is typically required."},{"q":"Is Currently holds valid temporary resident status or is eligible to restore status required?","a":"Check expiry date before filing"},{"q":"Is Submitted eligible permanent residence application required?","a":"Submitted eligible permanent residence application is typically required."},{"q":"Is Has AOR or proof PR application passed completeness check as required required?","a":"Do not use payment receipt alone"},{"q":"Is Current work permit expires within the allowed BOWP window or is already covered by maintained status required?","a":"Current work permit expires within the allowed BOWP window or is already covered by maintained status is typically required."},{"q":"Is Passport valid for requested work permit period required?","a":"Passport valid for requested work permit period is typically required."},{"q":"Is Provincial nomination has no employment restriction, if PNP-based required?","a":"Employer restriction may block open permit"},{"q":"Is No inadmissibility, misrepresentation, or unresolved removal issue required?","a":"No inadmissibility, misrepresentation, or unresolved removal issue is typically required."},{"q":"Is Correct work permit category and fees selected in IRCC portal required?","a":"Correct work permit category and fees selected in IRCC portal is typically required."},{"q":"What is the Processing time?","a":"3–5m — Varies by workload"},{"q":"What is the Government fee?","a":"CAD $255 — Verify on canada.ca"},{"q":"What is the Our approval rate?","a":"90% — ~82% benchmark"},{"q":"What is the Required docs?","a":"10 — + AOR and PR proof"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000017';

-- Canada – Study Permit Extension — 30 FAQs
-- Source: content/service-library/canada-study-permit-extension.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"When should the extension be filed?","a":"File before the current permit expires. IRCC often recommends applying at least 30 days before expiry, but earlier is better when documents are ready."},{"q":"Can the student keep studying after applying?","a":"If they applied before expiry and continue meeting permit conditions, they may be covered by maintained status while IRCC processes the extension."},{"q":"Can the student work while waiting?","a":"Work rights depend on the prior permit conditions and maintained status rules. Confirm before advising the client to continue work."},{"q":"What if the permit expired?","a":"Assess restoration eligibility immediately. The client may need to stop studying or working until status is restored."},{"q":"Is a new LOA required?","a":"Use a new LOA for a new program or DLI. For continuing students, current enrolment proof and expected completion date are usually important."},{"q":"How much money should be shown?","a":"Use current IRCC financial requirements plus unpaid tuition and living costs. Explain large deposits and sponsor sources."},{"q":"Does changing schools affect the extension?","a":"It can. Collect updated DLI evidence and ensure the client complied with IRCC rules for school changes."},{"q":"Can family members extend too?","a":"Dependants may need separate visitor, study, or work extensions. Screen each status independently."},{"q":"Is biometrics required again?","a":"Often biometrics remain valid for 10 years for temporary residence, but verify the client''s biometrics status and IRCC instructions."},{"q":"Will extension approval help PGWP later?","a":"It can support continuous lawful study, but PGWP eligibility depends on DLI, program, full-time status, and completion rules."},{"q":"What is Description for this service?","a":"Extension for students already in Canada who need more time on their study permit to continue or complete an eligible program at a Designated Learning Institution."},{"q":"What is Eligible applicants for this service?","a":"In Canada · Current study permit · Continuing studies or new DLI/program · Proof of funds · Applying before expiry where possible"},{"q":"What is Maintained status for this service?","a":"If filed before expiry, the client may remain in Canada while IRCC processes the extension under maintained status. Study and work rights depend on previous permit conditions."},{"q":"Important note on Maintained status?","a":"If filed before expiry, the client may remain in Canada while IRCC processes the extension under maintained status. Study and work rights depend on previous permit conditions."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Review new expiry date, study and work conditions, DLI obligations, and passport validity for the next extension or PGWP planning."},{"q":"Is Client is physically in Canada required?","a":"Client is physically in Canada is typically required."},{"q":"Is Current study permit is valid or client is within restoration period required?","a":"Expiry date drives urgency"},{"q":"Is Continues at a DLI or has valid new LOA from DLI required?","a":"Continues at a DLI or has valid new LOA from DLI is typically required."},{"q":"Is Proof of enrolment or transcript shows active study progress required?","a":"Proof of enrolment or transcript shows active study progress is typically required."},{"q":"Is Proof of funds covers tuition, living costs, and return transport required?","a":"Proof of funds covers tuition, living costs, and return transport is typically required."},{"q":"Is Passport valid beyond requested extension period required?","a":"Passport valid beyond requested extension period is typically required."},{"q":"Is No unauthorized work or study history required?","a":"No unauthorized work or study history is typically required."},{"q":"Is Medical exam completed if IRCC profile requires it required?","a":"Assess whether Medical exam completed if IRCC profile requires it is satisfied for this case."},{"q":"Is Academic gaps, program changes, or delayed completion explained required?","a":"Academic gaps, program changes, or delayed completion explained is typically required."},{"q":"What is the Processing time?","a":"6–12w — Check IRCC weekly"},{"q":"What is the Government fee?","a":"CAD $150 — Verify on canada.ca"},{"q":"What is the Our approval rate?","a":"91% — ~84% benchmark"},{"q":"What is the Required docs?","a":"11 — + enrolment proof"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000018';

-- Canada – Visitor Record (In-Canada Extension) — 30 FAQs
-- Source: content/service-library/canada-visitor-record.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Is a visitor record the same as a visitor visa?","a":"No. A visitor record extends status inside Canada. A TRV or eTA is used for travel to Canada."},{"q":"When should a visitor record be filed?","a":"File before the authorized stay expires. For entry without a stamp, calculate the default stay carefully unless another date was given."},{"q":"Can the client work on a visitor record?","a":"No. A visitor record does not authorize work unless a separate policy or permit applies."},{"q":"Can the client study on a visitor record?","a":"Only limited short-term study may be allowed in specific cases. Do not advise long-term study without a study permit."},{"q":"Can the client leave Canada while it is processing?","a":"Travel can abandon the practical purpose of the application and re-entry requires a valid TRV/eTA if applicable. Review before travel."},{"q":"How long should we request?","a":"Request a reasonable period supported by purpose, funds, insurance, and passport validity. Avoid arbitrary long requests."},{"q":"What if the client is waiting for another application?","a":"Explain the pending application and include proof, but still show temporary intent and funds."},{"q":"Can parents of students extend as visitors?","a":"Yes, if they show a genuine temporary purpose, funds, accommodation, and intention to leave or maintain legal status."},{"q":"What if the client has a prior refusal?","a":"Disclose it and address the refusal reason. Do not refile with the same weak explanation."},{"q":"Does approval guarantee future entry to Canada?","a":"No. Border entry is assessed separately, and a visitor record does not replace travel authorization."},{"q":"What is Description for this service?","a":"Visitor record application for temporary residents already in Canada who need to extend their stay as visitors or change conditions from another temporary status."},{"q":"What is Eligible applicants for this service?","a":"In Canada · Valid temporary resident status or restoration eligibility · Genuine temporary purpose · Funds for stay · Clear departure or next-status plan"},{"q":"What is Important limitation for this service?","a":"Visitor record does not authorize work or long-term study and does not guarantee re-entry after travel outside Canada."},{"q":"Important note on Important limitation?","a":"Visitor record does not authorize work or long-term study and does not guarantee re-entry after travel outside Canada."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Client receives a document with a new status expiry date. Review conditions and calendar the next exit or extension deadline."},{"q":"Is Client is physically in Canada required?","a":"Client is physically in Canada is typically required."},{"q":"Is Current visitor, student, or worker status is valid or restorable required?","a":"Check original entry date and permit expiry"},{"q":"Is Clear temporary reason for extended stay required?","a":"Clear temporary reason for extended stay is typically required."},{"q":"Is Proof of funds for extended visit required?","a":"Proof of funds for extended visit is typically required."},{"q":"Is Accommodation or host support evidence required?","a":"Accommodation or host support evidence is typically required."},{"q":"Is No unauthorized work or study planned required?","a":"No unauthorized work or study planned is typically required."},{"q":"Is Ties outside Canada or credible departure plan required?","a":"Ties outside Canada or credible departure plan is typically required."},{"q":"Is Passport valid for requested stay period required?","a":"Passport valid for requested stay period is typically required."},{"q":"Is Prior status history and refusals disclosed required?","a":"Prior status history and refusals disclosed is typically required."},{"q":"What is the Processing time?","a":"2–4m — Check IRCC"},{"q":"What is the Government fee?","a":"CAD $100 — Verify on canada.ca"},{"q":"What is the Our approval rate?","a":"89% — ~80% benchmark"},{"q":"What is the Required docs?","a":"9 — + reason for stay"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000019';

-- Canada – CAIPS / GCMS Notes Request — 30 FAQs
-- Source: content/service-library/canada-caips-notes.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"What are GCMS notes?","a":"They are internal immigration records and officer notes from IRCC systems, often used to understand refusals or case status."},{"q":"Are CAIPS and GCMS the same?","a":"Clients often use the terms together. GCMS is the modern system most IRCC notes come from; CAIPS is an older term still used colloquially."},{"q":"How long do notes take?","a":"ATIP requests are commonly targeted around 30 days, but extensions and delays happen. Check the official ATIP process."},{"q":"Can GCMS notes overturn a refusal?","a":"No. Notes help diagnose reasons. Any reconsideration, appeal, judicial review, or reapplication is separate."},{"q":"Who can request notes?","a":"Eligibility depends on access to information and privacy rules. Often an eligible requester in Canada submits with applicant consent."},{"q":"What documents are needed?","a":"Signed consent, applicant identity details, passport, refusal letter or application details, UCI, application number, and requester information."},{"q":"Can we order notes for an application still in process?","a":"Yes, but notes may be limited or outdated by the time received. Manage expectations."},{"q":"Will notes show the exact reason for refusal?","a":"Often they provide more detail than the refusal letter, but some information may be redacted or procedural."},{"q":"Should we wait for notes before reapplying?","a":"For refusals, notes are helpful. But if intake, visa, or legal deadlines are urgent, escalate and decide strategically."},{"q":"Can family members sign for the applicant?","a":"Only if legally authorized. Otherwise each adult applicant generally signs their own consent."},{"q":"What is Description for this service?","a":"Access to Information and Privacy request for CAIPS/GCMS notes, used to review officer notes, refusal rationale, application status, and case history for Canadian immigration files."},{"q":"What is Eligible applicants for this service?","a":"Applicant with signed consent · Eligible requester in Canada where required · Correct IRCC application identifiers · Identity proof"},{"q":"What is Service scope for this service?","a":"GCMS notes provide records and officer comments but do not overturn a refusal or speed up processing."},{"q":"Important note on Service scope?","a":"GCMS notes provide records and officer comments but do not overturn a refusal or speed up processing."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC) and Government of Canada ATIP Online Request Service"},{"q":"What is After release for this service?","a":"Counselor reviews notes for refusal reasons, missing evidence, credibility concerns, and next application strategy."},{"q":"Is Signed consent from applicant or authorized person required?","a":"Use current consent form"},{"q":"Is Requester eligibility confirmed for ATIP submission required?","a":"Requester eligibility confirmed for ATIP submission is typically required."},{"q":"Is Applicant identity details match IRCC records required?","a":"Applicant identity details match IRCC records is typically required."},{"q":"Is Application number, UCI, or file details available required?","a":"Application number, UCI, or file details available is typically required."},{"q":"Is Refusal letter or application history collected where relevant required?","a":"Refusal letter or application history collected where relevant is typically required."},{"q":"Is Applicant understands notes are not an appeal required?","a":"Applicant understands notes are not an appeal is typically required."},{"q":"Is Privacy authorization and service agreement on file required?","a":"Privacy authorization and service agreement on file is typically required."},{"q":"Is Correct department and record type selected in ATIP portal required?","a":"Correct department and record type selected in ATIP portal is typically required."},{"q":"Is Delivery email and client contact details verified required?","a":"Delivery email and client contact details verified is typically required."},{"q":"What is the Processing time?","a":"30d+ — ATIP timelines vary"},{"q":"What is the Government fee?","a":"CAD $5 — Verify on canada.ca"},{"q":"What is the Our completion rate?","a":"98% — Consent-driven service"},{"q":"What is the Required docs?","a":"8 — + consent form"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-00000000001a';

-- Canada – Spouse / Dependent Open Work Permit — 30 FAQs
-- Source: content/service-library/canada-spouse-dependent-owp.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can every spouse of a student get an open work permit?","a":"No. Eligibility depends on current IRCC rules, the student''s program and institution, and other conditions."},{"q":"Can every spouse of a worker get an open work permit?","a":"No. The principal worker''s occupation, permit type, and status must qualify under current policy."},{"q":"Is a marriage certificate enough?","a":"Usually not by itself. Provide relationship history, photos, communication, travel, financial ties, and family evidence where available."},{"q":"Can common-law partners apply?","a":"Yes, if they meet IRCC''s common-law definition and can prove cohabitation and genuine relationship."},{"q":"Can dependent children get open work permits?","a":"Only in limited circumstances. Many children need visitor or study status instead. Screen age and dependency rules carefully."},{"q":"Should the application be filed together with the principal applicant?","a":"Sometimes. It depends on timing, principal eligibility, documents, and risk. Joint filing can help context but is not always best."},{"q":"How long will the OWP be valid?","a":"Often tied to the principal applicant''s status and passport validity. IRCC decides the final duration."},{"q":"Can the applicant work while waiting?","a":"Only if they already have authorization and meet maintained status rules. Outside-Canada applicants cannot work until approved and admitted with proper status."},{"q":"What if there was a previous spouse OWP refusal?","a":"Order notes if useful, address refusal reasons directly, and strengthen principal eligibility and relationship evidence."},{"q":"Does approval lead to PR?","a":"No. OWP is temporary status. It may support Canadian work experience, but PR requires a separate pathway."},{"q":"What is Description for this service?","a":"Open work permit pathway for eligible spouses, common-law partners, or qualifying dependants linked to a principal applicant''s Canadian work, study, or immigration status."},{"q":"What is Eligible applicants for this service?","a":"Genuine spouse/common-law partner or eligible dependant · Principal applicant has qualifying status · Relationship documents · Funds and admissibility evidence"},{"q":"What is Rule sensitivity for this service?","a":"Eligibility for spouses of students and workers depends on current IRCC categories, program level, occupation, and principal status. Always verify current rules."},{"q":"Important note on Rule sensitivity?","a":"Eligibility for spouses of students and workers depends on current IRCC categories, program level, occupation, and principal status. Always verify current rules."},{"q":"What is Key authority for this service?","a":"Immigration, Refugees and Citizenship Canada (IRCC)"},{"q":"What is After approval for this service?","a":"Applicant may work for most employers in Canada subject to printed conditions. Review expiry alignment with principal applicant status."},{"q":"Is Principal applicant has valid qualifying status in Canada or approved pathway required?","a":"Principal applicant has valid qualifying status in Canada or approved pathway is typically required."},{"q":"Is Applicant is spouse, common-law partner, or qualifying dependant under IRCC rules required?","a":"Applicant is spouse, common-law partner, or qualifying dependant under IRCC rules is typically required."},{"q":"Is Relationship is genuine and well documented required?","a":"Marriage certificate alone may not be enough"},{"q":"Is Principal worker occupation, employer, or permit category qualifies where required required?","a":"Principal worker occupation, employer, or permit category qualifies where required is typically required."},{"q":"Is Principal student program and institution qualify where required required?","a":"Principal student program and institution qualify where required is typically required."},{"q":"Is Applicant passport valid for requested permit period required?","a":"Applicant passport valid for requested permit period is typically required."},{"q":"Is Applicant has no inadmissibility, misrepresentation, or undisclosed refusal issue required?","a":"Applicant has no inadmissibility, misrepresentation, or undisclosed refusal issue is typically required."},{"q":"Is Funds or family support evidence available for settlement and stay required?","a":"Funds or family support evidence available for settlement and stay is typically required."},{"q":"Is Medical exam or biometrics completed if required required?","a":"Assess whether Medical exam or biometrics completed if required is satisfied for this case."},{"q":"What is the Processing time?","a":"3–5m — Varies by applicant location"},{"q":"What is the Government fee?","a":"CAD $255 — Verify on canada.ca"},{"q":"What is the Our approval rate?","a":"88% — ~76% benchmark"},{"q":"What is the Required docs?","a":"13 — + relationship proof"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-00000000001b';

-- UK – Student Visa (Student Route) — 30 FAQs
-- Source: content/service-library/uk-student-visa.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee Student visa approval?","a":"No. UKVI assesses each application. Strong CAS and funds help but approval is never guaranteed."},{"q":"How much funds for London vs outside London?","a":"Living costs differ—verify current amounts on gov.uk. Plus remaining tuition after deposit shown on CAS."},{"q":"What is the 28-day rule?","a":"Funds must remain at or above required amount for 28 consecutive days ending no more than 31 days before application."},{"q":"Can spouse join on Student visa?","a":"Dependants allowed only if course meets specific criteria (e.g., postgraduate level certain duration). Check current rules."},{"q":"Is IELTS UKVI mandatory?","a":"If SELT required, must be UKVI-approved test from approved centre. Some nationals/courses may be exempt."},{"q":"When to apply?","a":"Up to 6 months before course start if applying from outside UK. Do not apply without valid CAS."},{"q":"Can student work?","a":"Limited hours during term; rules on gov.uk. Cannot work as professional sportsperson or doctor in training."},{"q":"What after course completion?","a":"Discuss Graduate Route eligibility separately—requires successful completion at eligible institution."},{"q":"What is Description for this service?","a":"Student Route visa for study at a UK institution holding a valid sponsor licence. Requires Confirmation of Acceptance for Studies (CAS) and online UKVI application."},{"q":"What is Eligible applicants for this service?","a":"Valid CAS · Proof of funds · English at required level · Genuine student intent · TB test if from listed country"},{"q":"What is Financial requirement for this service?","a":"Tuition minus deposit paid + living costs (London vs outside London rates). 28-day funds rule applies."},{"q":"Important note on Financial requirement?","a":"Tuition minus deposit paid + living costs (London vs outside London rates). 28-day funds rule applies."},{"q":"What is Key authority for this service?","a":"UK Visas and Immigration (UKVI) — Home Office"},{"q":"What is After approval for this service?","a":"BRP or digital status; maintain attendance, sponsor reporting, and work hour limits."},{"q":"Is CAS from licensed UK sponsor required?","a":"CAS number valid and unused"},{"q":"Is Financial requirement met (28-day rule) required?","a":"Funds held 28 consecutive days"},{"q":"Is English language at SELT level (if required) required?","a":"IELTS UKVI or exempt pathway"},{"q":"Is TB test certificate (if applicable) required?","a":"Required for Indian nationals"},{"q":"Is ATAS certificate (if course requires) required?","a":"Check CAS and course code"},{"q":"Is Genuine student / credible study plan required?","a":"Genuine student / credible study plan is typically required."},{"q":"Is Immigration history disclosed required?","a":"Immigration history disclosed is typically required."},{"q":"What is the Processing time?","a":"3–8w — Outside UK standard"},{"q":"What is the Government fee?","a":"£524 — + IHS per year of course"},{"q":"What is the Our approval rate?","a":"89% — ~76% industry benchmark"},{"q":"What is the Required docs?","a":"13 — + financial evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & IHS"},{"q":"What if the client has 28-day funds rule breach?","a":"Maintain required balance 28 days; use dated bank statements"},{"q":"Why is 28-day funds rule breach a problem?","a":"Funds not held continuously for 28 days or balance drops below threshold."},{"q":"What if the client has CAS / course mismatch?","a":"Align CAS course with academic progression; strong personal statement"},{"q":"Why is CAS / course mismatch a problem?","a":"Course level inconsistent with prior study or career plan."}]'::jsonb
),
updated_at = now()
