  '[{"q":"Can we guarantee Skilled Worker visa?","a":"No. UKVI verifies sponsor, salary, and points. Never promise approval."},{"q":"What is CoS?","a":"Certificate of Sponsorship—electronic record from licensed employer assigning sponsorship."},{"q":"Salary threshold 2026?","a":"Verify current general threshold and going rates on gov.uk—rules updated in 2024."},{"q":"Can switch employers?","a":"New CoS and application generally required for new employer."},{"q":"Spouse can work?","a":"Partner dependants typically can work—verify dependant visa conditions."},{"q":"Path to ILR?","a":"Generally 5 years on Skilled Worker route—verify current ILR requirements."},{"q":"Healthcare surcharge?","a":"IHS payable for visa duration—use gov.uk calculator."},{"q":"Can apply from India?","a":"Yes, entry clearance from outside UK with CoS and job offer."},{"q":"What is Description for this service?","a":"Work visa for skilled job offer from UK employer with valid sponsor licence. Requires Certificate of Sponsorship (CoS) and meeting 70-point criteria including salary threshold."},{"q":"What is Eligible applicants for this service?","a":"Job offer from licensed sponsor · CoS reference · RQF Level 3+ skilled occupation · English B1 · Salary at going rate or minimum threshold"},{"q":"What is Salary threshold for this service?","a":"General threshold £38,700 (2024+) or occupation-specific going rate—whichever is higher. Verify current rules for 2026."},{"q":"Important note on Salary threshold?","a":"General threshold £38,700 (2024+) or occupation-specific going rate—whichever is higher. Verify current rules for 2026."},{"q":"What is Key authority for this service?","a":"UK Visas and Immigration (UKVI)"},{"q":"What is After approval for this service?","a":"Work for sponsoring employer; visa tied to CoS. Pathway to ILR after 5 years typically."},{"q":"Is Certificate of Sponsorship from licensed sponsor required?","a":"Certificate of Sponsorship from licensed sponsor is typically required."},{"q":"Is Job at RQF Level 3+ (eligible SOC code) required?","a":"Job at RQF Level 3+ (eligible SOC code) is typically required."},{"q":"Is Salary meets threshold/going rate required?","a":"Salary meets threshold/going rate is typically required."},{"q":"Is English B1 (SELT or exempt) required?","a":"English B1 (SELT or exempt) is typically required."},{"q":"Is TB test (India) required?","a":"Assess whether TB test (India) is satisfied for this case."},{"q":"Is Maintenance funds (if applicable) required?","a":"Maintenance funds (if applicable) is typically required."},{"q":"Is 70 points total achieved required?","a":"70 points total achieved is typically required."},{"q":"What is the Processing time?","a":"3–8w — Outside UK"},{"q":"What is the Government fee?","a":"£719+ — + IHS per year"},{"q":"What is the Our approval rate?","a":"91% — ~83% benchmark"},{"q":"What is the Required docs?","a":"14 — + CoS & TB test"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & IHS"},{"q":"What if the client has Salary below going rate?","a":"Verify going rate for SOC code; negotiate salary with employer"},{"q":"Why is Salary below going rate a problem?","a":"Offered salary below SOC-specific or general threshold."},{"q":"What if the client has Unlicensed or suspended sponsor?","a":"Check sponsor register before CoS assignment"},{"q":"Why is Unlicensed or suspended sponsor a problem?","a":"Employer sponsor licence expired or revoked."}]'::jsonb
