-- USA – Student Visa (F-1) — 30 FAQs
-- Source: content/service-library/usa-student-visa.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee F-1 approval?","a":"No. Consular officers decide at interview. We prepare the file and coach for interview but never promise approval."},{"q":"How much funds to show?","a":"Typically tuition + living per I-20 for first year. Verify amount on I-20 financial page; include credible sponsor or loan evidence."},{"q":"What is 214(b)?","a":"Immigration law presumes immigrant intent. F-1 applicants must convince officer they will return after studies—ties, funds, and credible study plan matter."},{"q":"Can spouse accompany on F-2?","a":"F-2 dependants may apply separately. F-2 cannot work. Assess funds for entire family."},{"q":"When to pay SEVIS fee?","a":"Before interview, at least 3 days prior recommended. Bring I-901 receipt to embassy."},{"q":"How soon can client enter USA?","a":"No earlier than 30 days before I-20 program start date on valid F-1 visa."},{"q":"What if refused under 214(b)?","a":"No appeal. Reapply when circumstances materially improve—stronger ties, different program, or better funds."},{"q":"Is interview mandatory for renewals?","a":"Most Indian applicants attend interview. Check embassy guidance for specific renewal rules."},{"q":"What is Description for this service?","a":"F-1 non-immigrant visa for full-time academic study at a US institution certified by SEVP. Requires valid I-20, SEVIS payment, DS-160, and consular interview."},{"q":"What is Eligible applicants for this service?","a":"Valid I-20 from SEVP school · Proof of funds · English readiness · Non-immigrant intent · Clean immigration history"},{"q":"What is Interview focus for this service?","a":"Consular officer assesses genuine student intent, funds, and ties to India. Short, clear answers work better than memorised scripts."},{"q":"Important note on Interview focus?","a":"Consular officer assesses genuine student intent, funds, and ties to India. Short, clear answers work better than memorised scripts."},{"q":"What is Key authority for this service?","a":"US Department of State (embassy/consulate) · SEVIS/ICE for I-901"},{"q":"What is After approval for this service?","a":"F-1 visa foil in passport; enter US no earlier than 30 days before I-20 start. Maintain full-time enrollment and SEVIS compliance."},{"q":"Is Form I-20 from SEVP-certified school required?","a":"Program and start date must be realistic"},{"q":"Is SEVIS I-901 fee paid required?","a":"Receipt required for interview"},{"q":"Is DS-160 completed accurately required?","a":"Must match I-20 and documents"},{"q":"Is Proof of financial support required?","a":"Covers tuition + living for at least first year"},{"q":"Is English proficiency (as required by school) required?","a":"TOEFL/IELTS/Duolingo per I-20"},{"q":"Is Non-immigrant intent / ties to India required?","a":"Critical for 214(b) interview"},{"q":"Is No prior visa fraud or serious inadmissibility required?","a":"No prior visa fraud or serious inadmissibility is typically required."},{"q":"What is the Processing time?","a":"2–8w — Post-interview; slot wait extra"},{"q":"What is the Government fee?","a":"USD $535 — MRV $185 + SEVIS $350"},{"q":"What is the Our approval rate?","a":"84% — ~70% industry benchmark"},{"q":"What is the Required docs?","a":"12 — + financial evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has Weak non-immigrant intent (214(b))?","a":"Course-specific study plan; tie program to India career; practice concise interview answers"},{"q":"Why is Weak non-immigrant intent (214(b)) a problem?","a":"Vague return plan, course mismatch, or answers suggesting permanent stay intent."},{"q":"What if the client has Insufficient or unseasoned funds?","a":"4–6 month bank history; sponsor ITR + CA statement; education loan sanction letter"},{"q":"Why is Insufficient or unseasoned funds a problem?","a":"Large recent deposits, sponsor income not matching funds, or weak loan documentation."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000031';

-- USA – Visitor Visa (B1/B2) — 30 FAQs
-- Source: content/service-library/usa-visitor-visa.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee B1/B2 approval?","a":"No. Consular officers decide at interview based on individual assessment."},{"q":"What documents to carry to interview?","a":"Passport, DS-160 confirmation, photo, appointment letter, plus supporting docs—employment, funds, invitation if applicable. Officer may not review all."},{"q":"How to overcome 214(b)?","a":"Demonstrate strong ties, clear temporary purpose, credible funds, and consistent honest answers—not memorised scripts."},{"q":"Can refused applicant reapply?","a":"Yes anytime, but success requires materially changed circumstances or stronger evidence."},{"q":"Does B1/B2 allow work?","a":"No. Employment requires appropriate work visa. B1 allows limited business activities—not US labour market work."},{"q":"How long can visitor stay?","a":"Admission period set at port of entry—often up to 6 months. Must not overstay."},{"q":"Is invitation letter required?","a":"Not mandatory but helpful for family visits. Host''s status proof strengthens file."},{"q":"Ten-year visa means 10-year stay?","a":"No. Visa validity differs from permitted stay per entry. Each entry is subject to CBP admission."},{"q":"What is Description for this service?","a":"B1 (business) and B2 (tourism/medical) combined visa for temporary visits to the United States. Indian nationals apply via DS-160 and mandatory consular interview."},{"q":"What is Eligible applicants for this service?","a":"Temporary visit purpose · Strong ties to India · Sufficient funds · Clean immigration history · Honest DS-160"},{"q":"What is Interview reality for this service?","a":"Most decisions made in short interview. Officer assesses intent, ties, and credibility—not document volume alone."},{"q":"Important note on Interview reality?","a":"Most decisions made in short interview. Officer assesses intent, ties, and credibility—not document volume alone."},{"q":"What is Key authority for this service?","a":"US Department of State — Embassy/Consulate in India"},{"q":"What is After approval for this service?","a":"Visa foil in passport; officer at port of entry decides admission length (often up to 6 months). No work permitted."},{"q":"Is Valid passport required?","a":"6+ months validity recommended"},{"q":"Is Clear temporary purpose required?","a":"Tourism, family, business meeting—not employment"},{"q":"Is Strong ties to India required?","a":"Job, business, property, family"},{"q":"Is Proof of funds for trip required?","a":"Bank statements, ITR, sponsor letter"},{"q":"Is DS-160 completed accurately required?","a":"Must match interview answers"},{"q":"Is No prior visa fraud required?","a":"No prior visa fraud is typically required."},{"q":"Is Interview appointment booked required?","a":"Via ustraveldocs.com"},{"q":"What is the Processing time?","a":"1–4w — After interview; slot wait extra"},{"q":"What is the Government fee?","a":"USD $185 — MRV non-refundable"},{"q":"What is the Our approval rate?","a":"72% — ~58% industry benchmark"},{"q":"What is the Required docs?","a":"8 — + purpose-specific"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"},{"q":"What if the client has Weak ties to India?","a":"Employment letter, business registration, property, family dependencies"},{"q":"Why is Weak ties to India a problem?","a":"Unemployed, no assets, young single applicant with vague purpose."},{"q":"What if the client has 214(b) — immigrant intent signals?","a":"Clear temporary purpose; return date; no employment intent"},{"q":"Why is 214(b) — immigrant intent signals a problem?","a":"Mentions working in USA, long stay without reason, or visiting fiancé without clear plan."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000032';

-- USA – Spouse / Fiancé Visa (K-1 / CR-1 / IR-1) — 30 FAQs
-- Source: content/service-library/usa-spouse-visa.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"K-1 or CR-1—which is better?","a":"Depends on whether couple is already married and timeline preferences. CR-1/IR-1 grants immigrant visa directly; K-1 requires marriage in US then adjustment. No universal ''better''—assess case."},{"q":"Can we guarantee approval?","a":"No. USCIS, NVC, and embassy each review. Genuine relationships can still face delays or requests for evidence."},{"q":"How long total process?","a":"Often 12–24 months depending on pathway, service center, and embassy backlog. Check current processing times on uscis.gov."},{"q":"Can fiancé work on K-1?","a":"K-1 must marry within 90 days and file for work authorisation through adjustment of status—cannot work immediately on entry."},{"q":"What is conditional green card?","a":"If marriage under 2 years at entry, CR-1 recipient gets 2-year conditional card; must file I-751 to remove conditions."},{"q":"Is joint sponsor allowed?","a":"Yes, when petitioner income insufficient for I-864. Joint sponsor must meet income requirements and submit tax returns."},{"q":"What if petitioner was previously married?","a":"Must provide divorce decrees or death certificates for all prior marriages—both petitioner and beneficiary."},{"q":"Can beneficiary visit on B2 during processing?","a":"Risky—214(b) applies and immigrant intent can cause B2 refusal. Counsel honestly on risks."},{"q":"What is Description for this service?","a":"Family-based immigration for foreign spouse or fiancé of US citizen. CR-1/IR-1 for married couples (immigrant visa); K-1 for fiancés to marry in US within 90 days of entry."},{"q":"What is Eligible applicants for this service?","a":"US citizen petitioner · Valid marriage or bona fide engagement · Genuine relationship · Medical and police clearances · Affidavit of support"},{"q":"What is K-1 vs CR-1/IR-1 for this service?","a":"K-1: not yet married, faster initial petition but must marry in US and adjust status. CR-1/IR-1: already married, immigrant visa with conditional PR if marriage under 2 years."},{"q":"Important note on K-1 vs CR-1/IR-1?","a":"K-1: not yet married, faster initial petition but must marry in US and adjust status. CR-1/IR-1: already married, immigrant visa with conditional PR if marriage under 2 years."},{"q":"What is Key authority for this service?","a":"USCIS · National Visa Center (NVC) · US Embassy New Delhi/Mumbai/Chennai/Hyderabad/Kolkata"},{"q":"What is After approval for this service?","a":"Enter US as immigrant (CR-1/IR-1) or K-1 then marry and file I-485. Understand conditional green card rules if applicable."},{"q":"Is US citizen petitioner (not green card holder for K-1) required?","a":"LPR sponsors spouse via different family preference—confirm category"},{"q":"Is Legally valid marriage or qualifying engagement required?","a":"Marriage cert or proof of meeting in person within 2 years for K-1"},{"q":"Is Genuine relationship evidence required?","a":"Photos, communication, visits, joint plans"},{"q":"Is I-864 affidavit of support required?","a":"Petitioner income 125% poverty guideline or joint sponsor"},{"q":"Is Civil documents (birth, marriage, police) required?","a":"NVC document collection phase"},{"q":"Is Medical exam by panel physician required?","a":"Before embassy interview"},{"q":"Is DS-260 and embassy interview required?","a":"Final stage before visa issuance"},{"q":"What is the Processing time?","a":"12–24m — USCIS + NVC + embassy"},{"q":"What is the Government fee?","a":"USD $1,000+ — Petition + NVC + medical"},{"q":"What is the Our approval rate?","a":"88% — ~78% industry benchmark"},{"q":"What is the Required docs?","a":"20 — + civil documents"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & medical"},{"q":"What if the client has Bona fide relationship not credible?","a":"Document meeting history, visits, communication logs, joint financial plans"},{"q":"Why is Bona fide relationship not credible a problem?","a":"Minimal contact history, large age gap unexplained, or marriage soon after online-only relationship."},{"q":"What if the client has Insufficient I-864 income?","a":"Joint sponsor with tax returns, or petitioner additional evidence of assets"},{"q":"Why is Insufficient I-864 income a problem?","a":"Petitioner income below 125% poverty line without joint sponsor."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000033';

-- USA – Green Card (Employment & Family) — 30 FAQs
-- Source: content/service-library/usa-green-card.json

UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee green card?","a":"No. Multi-step process with DOL, USCIS, and visa availability. Never promise approval or timeline."},{"q":"How long for Indians EB-2?","a":"Check current Visa Bulletin—often many years backlog. Dates move monthly."},{"q":"What is PERM?","a":"Labor certification proving no qualified US workers available—required for most EB-2/EB-3."},{"q":"Can spouse work during wait?","a":"Depends on status—H-4 EAD, L-2, or EAD with pending I-485 if eligible."},{"q":"What is priority date?","a":"Date PERM filed or I-140 receipt—determines place in queue per Visa Bulletin."},{"q":"EB-1 vs EB-2?","a":"EB-1 for extraordinary ability/multinational managers—no PERM. EB-2 typically needs PERM unless NIW."},{"q":"What is NIW?","a":"National Interest Waiver—EB-2 without PERM if work benefits US national interest."},{"q":"Family-based options?","a":"I-130 through US citizen/LPR relatives—preference categories have own backlogs."},{"q":"What is Description for this service?","a":"Lawful permanent residence (green card) via employment sponsorship (EB-1/2/3/5) or family petition (I-130). Multi-step process involving PERM, I-140, priority date, and I-485 or consular processing."},{"q":"What is Eligible applicants for this service?","a":"Qualifying job offer/sponsor (EB) or qualifying family relationship · PERM for most EB-2/3 · Priority date current per Visa Bulletin · Medical and character clearances"},{"q":"What is India backlog reality for this service?","a":"Indian-born EB-2/EB-3 applicants often wait years after I-140 approval for priority date to become current. Monitor Visa Bulletin monthly."},{"q":"Important note on India backlog reality?","a":"Indian-born EB-2/EB-3 applicants often wait years after I-140 approval for priority date to become current. Monitor Visa Bulletin monthly."},{"q":"What is Key authority for this service?","a":"USCIS · Department of Labor (PERM) · Department of State (Visa Bulletin/NVC)"},{"q":"What is After approval for this service?","a":"Receive green card; maintain residence; eligible for citizenship after qualifying period (typically 5 years)."},{"q":"Is Qualifying EB category or family relationship required?","a":"Qualifying EB category or family relationship is typically required."},{"q":"Is Employer sponsorship / PERM (EB-2/3) required?","a":"PERM adds 12–18 months"},{"q":"Is I-140 approved required?","a":"Assess whether I-140 approved is satisfied for this case."},{"q":"Is Priority date current (Visa Bulletin) required?","a":"Check monthly bulletin"},{"q":"Is I-485 or consular processing eligible required?","a":"Assess whether I-485 or consular processing eligible is satisfied for this case."},{"q":"Is Medical exam completed required?","a":"Assess whether Medical exam completed is satisfied for this case."},{"q":"Is No serious inadmissibility required?","a":"No serious inadmissibility is typically required."},{"q":"What is the Processing time?","a":"2–10+y — Category & country dependent"},{"q":"What is the Government fee?","a":"USD $2,000+ — Multiple forms over process"},{"q":"What is the Our approval rate?","a":"85% — ~78% benchmark"},{"q":"What is the Required docs?","a":"22 — + employer docs for EB"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & legal"},{"q":"What if the client has Priority date not current?","a":"Monitor Visa Bulletin; maintain H-1B/status; set realistic timeline"},{"q":"Why is Priority date not current a problem?","a":"Client expects green card but Visa Bulletin shows years of backlog."},{"q":"What if the client has PERM recruitment issues?","a":"Ensure PERM compliance; experienced immigration attorney for PERM"},{"q":"Why is PERM recruitment issues a problem?","a":"DOL audits or inadequate recruitment advertising."}]'::jsonb
),
updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000034';

-- Australia – Student Visa (Subclass 500) — 30 FAQs
